function a(r){return r.replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#39;")}function t(r){return r.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/\*(.+?)\*/g,"<em>$1</em>").replace(/`(.+?)`/g,"<code>$1</code>").replace(/\[(.+?)\]\((https?:\/\/[^\s)]+)\)/g,'<a href="$2" target="_blank" rel="noreferrer">$1</a>')}function s(r=""){return a(r).split(/\n{2,}/).map(e=>e.trim()).filter(Boolean).map(e=>e.startsWith("- ")?`<ul>${e.split(`
`).map(l=>l.replace(/^- /,"").trim()).filter(Boolean).map(l=>`<li>${t(l)}</li>`).join("")}</ul>`:e.startsWith("## ")?`<h3>${t(e.replace(/^## /,""))}</h3>`:e.startsWith("# ")?`<h2>${t(e.replace(/^# /,""))}</h2>`:`<p>${t(e.replaceAll(`
`,"<br />"))}</p>`).join("")}export{s as r};
